UPDATE topic SET
  content = $topic126$[{"id":"84a4db31-0cf2-4ecc-b4d7-65c606e5a145","type":"heading","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left","level":3,"isToggleable":false},"content":[{"type":"text","text":"프로젝트 개요","styles":{}}],"children":[]},{"id":"f5b937cf-cd38-4d77-825d-a1a0329bd3f2","type":"divider","props":{},"children":[]},{"id":"22b56a84-528e-41af-9d1e-446c79fd2688","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"커뮤니티앱(ComunityApp)은 Expo SDK 52와 React Native로 제작한 크로스 플랫폼 모바일 커뮤니티 애플리케이션입니다. iOS·Android 네이티브 빌드와 Expo Go, 웹 타깃을 동시에 지원하는 Expo의 장점을 활용해, 웹 개발 경험을 모바일 영역으로 확장하는 것을 목표로 했습니다.","styles":{}}],"children":[]},{"id":"bd779540-57e6-4c64-8000-d8e60dabf66b","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"라우팅은 Expo Router의 파일 기반 convention을 따릅니다. `app/(tabs)/` 아래 index(홈), my(마이), setting(설정) 탭을 두고, `app/auth/`에서 로그인·회원가입 플로우를 분리했습니다. TanStack Query로 API 응답을 관리하고, React Hook Form으로 폼 상태를 다루며, expo-secure-store에 토큰을 안전하게 보관하는 전형적인 RN 스택을 적용했습니다.","styles":{}}],"children":[]},{"id":"8e778f47-fbe8-4848-8dbd-35ebb86ec285","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"GitHub: ","styles":{"bold":true}},{"type":"text","text":"kimkijun0226/ComunityApp","styles":{}}],"children":[]},{"id":"183d99c4-478b-42c6-a906-76ab46caf4de","type":"image","props":{"backgroundColor":"default","textAlignment":"left","name":"","url":"https://picsum.photos/seed/community-overview/1200/675","caption":"[임시 이미지] 커뮤니티앱 탭 구조","showPreview":true,"previewWidth":720},"children":[]},{"id":"96cdfbd3-eaf6-4d78-afae-22a4c8233e01","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[],"children":[]},{"id":"7e527f75-68d7-4cfc-94e6-e7ad4dffaef3","type":"heading","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left","level":3,"isToggleable":false},"content":[{"type":"text","text":"기술 스택 상세","styles":{}}],"children":[]},{"id":"ed65feac-6460-42bc-8008-c5e5fa90b7aa","type":"divider","props":{},"children":[]},{"id":"6cafb3ab-3a33-4a06-b887-0b95da60b81c","type":"bulletListItem","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"런타임: Expo SDK 52, React Native, TypeScript","styles":{}}],"children":[]},{"id":"c56dfc81-958e-4af7-b8f6-843e79cf8b27","type":"bulletListItem","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"네비게이션: Expo Router — app/ 디렉터리 파일 = 라우트, (tabs) 그룹으로 하단 탭 바","styles":{}}],"children":[]},{"id":"5b90d911-87d9-4be6-9e5e-e64c2566d1f1","type":"bulletListItem","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"데이터: TanStack Query, Axios — REST API 호출·캐싱·리트라이","styles":{}}],"children":[]},{"id":"359a42d7-6e95-44e1-98ea-805938cede30","type":"bulletListItem","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"폼: React Hook Form — 로그인·게시글·프로필 입력","styles":{}}],"children":[]},{"id":"ff1ca49d-65a1-492f-b4c9-6b30c41faf20","type":"bulletListItem","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"네이티브: expo-secure-store(토큰), expo-haptics(터치 피드백), React Navigation 제스처","styles":{}}],"children":[]},{"id":"f9855296-6886-43eb-ae44-8b3bc05b4af0","type":"image","props":{"backgroundColor":"default","textAlignment":"left","name":"","url":"https://picsum.photos/seed/community-stack/1200/675","caption":"[임시 이미지] Expo·Router 스택","showPreview":true,"previewWidth":720},"children":[]},{"id":"d5deddcb-a36c-4ffd-a8b7-c9d959e9cb06","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[],"children":[]},{"id":"5d4bfafc-b004-4965-810b-5f6adc456382","type":"heading","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left","level":3,"isToggleable":false},"content":[{"type":"text","text":"주요 구현","styles":{}}],"children":[]},{"id":"63d3c0d5-df6b-479d-9ba3-3c2ae75dea56","type":"divider","props":{},"children":[]},{"id":"8f3f70aa-f916-42dc-a8ef-604ba9af6a56","type":"bulletListItem","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"탭 네비게이션 — 홈 피드, 마이 페이지(내 글·프로필), 설정(알림·테마·로그아웃)","styles":{}}],"children":[]},{"id":"14ffb401-c313-40e2-93e3-79345fa66b56","type":"bulletListItem","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"auth 스택 — 비로그인 시 auth 레이아웃으로 redirect, 로그인 후 tabs 복귀","styles":{}}],"children":[]},{"id":"82243947-484f-47f4-a334-069555a389a3","type":"bulletListItem","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"공통 컴포넌트 — 플랫폼별 StyleSheet, Pressable + haptics로 네이티브한 터치감","styles":{}}],"children":[]},{"id":"d5454e36-f96b-44b7-bde2-8712ea0e66f1","type":"bulletListItem","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"웹·앱 공유 코드베이스 — Platform.OS 분기 최소화, Expo web 빌드로 데스크톱 미리보기","styles":{}}],"children":[]},{"id":"a8606132-b30f-4346-9646-db9bcd668293","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[],"children":[]},{"id":"4116705a-a868-4f78-949d-0af76187a992","type":"heading","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left","level":3,"isToggleable":false},"content":[{"type":"text","text":"회고","styles":{}}],"children":[]},{"id":"e873dda5-e0f6-494f-ac58-187cebf78efe","type":"divider","props":{},"children":[]},{"id":"f238ef90-31bd-471d-b75a-d01d3afb5d4b","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"웹 중심으로 일해 오다가 Expo Router와 EAS Build 파이프라인을 직접 맞춰 보며, ‘같은 React 패러다임으로 모바일까지’ 확장하는 감각을 익힌 프로젝트입니다. 커뮤니티 도메인(피드·마이·설정)을 탭 단위로 쪼개 설계한 경험은 이후 My Page 같은 웹 서비스의 IA를 잡을 때도 참고가 되었습니다.","styles":{}}],"children":[]},{"id":"26497cf4-9dbd-4951-bf46-617655f45c5d","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[],"children":[]},{"id":"47097170-90b5-492a-963b-41cef3801400","type":"heading","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left","level":3,"isToggleable":false},"content":[{"type":"text","text":"페이지·화면별 상세","styles":{}}],"children":[]},{"id":"8271826b-1573-4738-91e5-0203e0e970e8","type":"divider","props":{},"children":[]},{"id":"087a6be6-cb08-42de-bfe0-3443ee3052d0","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"아래는 실제 서비스를 구성하는 주요 화면 단위 설명입니다. 각 섹션마다 임시 스크린샷 이미지를 넣어 두었으며, 추후 실제 캡처로 교체할 예정입니다.","styles":{}}],"children":[]},{"id":"fe7bbf87-333c-4939-8934-0d442de706ef","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[],"children":[]},{"id":"cdf1f8e8-6879-433e-a496-c4a26ebaafbe","type":"heading","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left","level":4,"isToggleable":false},"content":[{"type":"text","text":"홈 탭 — app/(tabs)/index","styles":{}}],"children":[]},{"id":"786098b5-7f2d-44a5-86e5-5631abd81ce2","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"커뮤니티 피드의 메인 화면입니다. 게시글 목록을 FlatList로 렌더하고, 당겨서 새로고침·무한 스크롤로 추가 로드를 구현할 수 있는 구조입니다.","styles":{}}],"children":[]},{"id":"8e3aa315-20eb-4182-afb7-790dc2030aaa","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"각 카드에는 작성자, 본문 미리보기, 좋아요·댓글 수가 표시되며, 탭하면 상세로 이동합니다.","styles":{}}],"children":[]},{"id":"b71b8c34-a920-412c-9af5-66448841a78e","type":"image","props":{"backgroundColor":"default","textAlignment":"left","name":"","url":"https://picsum.photos/seed/community-home/1200/675","caption":"[임시] 홈 피드","showPreview":true,"previewWidth":720},"children":[]},{"id":"6b365379-090f-4e88-acf2-1a7997d560ed","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[],"children":[]},{"id":"712db36d-6566-4ea7-a893-a91f7277a98b","type":"heading","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left","level":4,"isToggleable":false},"content":[{"type":"text","text":"마이 탭 — app/(tabs)/my","styles":{}}],"children":[]},{"id":"cf142fbb-0163-4a8c-a166-7f0c4af61a3e","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"로그인한 사용자의 프로필 요약, 내가 쓴 글, 북마크 등을 모아 보여 주는 공간입니다. 아바타·닉네임·소개 편집으로 연결됩니다.","styles":{}}],"children":[]},{"id":"dab06b8c-c216-4314-aa87-35306c4411b1","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"비로그인 시 로그인 유도 CTA를 노출하는 패턴을 사용합니다.","styles":{}}],"children":[]},{"id":"76b7c10a-2d38-44ea-8bad-6edec7fe639f","type":"image","props":{"backgroundColor":"default","textAlignment":"left","name":"","url":"https://picsum.photos/seed/community-my/1200/675","caption":"[임시] 마이 페이지","showPreview":true,"previewWidth":720},"children":[]},{"id":"8466b6db-277b-48a1-9b27-6737ac8d8589","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[],"children":[]},{"id":"bdbd94b2-a165-4104-b2aa-4501ac6e725a","type":"heading","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left","level":4,"isToggleable":false},"content":[{"type":"text","text":"설정 탭 — app/(tabs)/setting","styles":{}}],"children":[]},{"id":"f462f70f-e1ac-42f0-b790-65da78061ada","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"알림 on/off, 다크 모드(시스템 연동), 버전 정보, 로그아웃 등 앱 설정을 모아 둔 화면입니다.","styles":{}}],"children":[]},{"id":"01450cf8-87b2-4d46-9582-bb81e8a9d8d8","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"expo-secure-store에 저장된 세션을 지우고 auth 스택으로 보내는 로그아웃 플로우가 포함됩니다.","styles":{}}],"children":[]},{"id":"1a7e9a3f-3fc7-4dce-8948-154d00dec286","type":"image","props":{"backgroundColor":"default","textAlignment":"left","name":"","url":"https://picsum.photos/seed/community-setting/1200/675","caption":"[임시] 설정 화면","showPreview":true,"previewWidth":720},"children":[]},{"id":"dbc6b6f7-372d-4869-ad71-67e8eae4cf8e","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[],"children":[]},{"id":"a0ddc601-1f51-4cd3-8399-91ac64731717","type":"heading","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left","level":4,"isToggleable":false},"content":[{"type":"text","text":"인증 — app/auth/","styles":{}}],"children":[]},{"id":"ae48234d-cb78-4209-8dfe-8eacd1995a99","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"로그인·회원가입 스크린을 스택으로 구성합니다. React Hook Form + Axios로 백엔드 인증 API를 호출하고, 성공 토큰을 secure-store에 저장합니다.","styles":{}}],"children":[]},{"id":"58186bbe-62ed-4ba5-8ad3-f4f946b5fd97","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"인증 상태는 Context 또는 Zustand로 tabs 레이아웃과 공유합니다.","styles":{}}],"children":[]},{"id":"5bb77abe-c902-4c3e-9d4c-994db3f411c5","type":"image","props":{"backgroundColor":"default","textAlignment":"left","name":"","url":"https://picsum.photos/seed/community-auth/1200/675","caption":"[임시] 로그인 화면","showPreview":true,"previewWidth":720},"children":[]},{"id":"98c4c13c-4e03-41dd-93f6-90b490bd6045","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[],"children":[]}]$topic126$,
  thumbnail = 'https://picsum.photos/seed/community-app/1200/630'
