UPDATE topic SET
  content = $topic127$[{"id":"e622b96e-1fbc-4adc-8a2c-daee390d14d3","type":"heading","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left","level":3,"isToggleable":false},"content":[{"type":"text","text":"프로젝트 개요","styles":{}}],"children":[]},{"id":"58f6030a-3238-4cea-8f1a-f3bc3186fdc8","type":"divider","props":{},"children":[]},{"id":"6733abbc-d033-4da7-b964-da58900f078a","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"2026년에 새로 제작한 프론트엔드 개발자 포트폴리오 웹사이트입니다. About · Experience · Projects 세 섹션을 한 페이지 세로 스크롤로 이어 붙였고, CSS scroll-snap과 커스텀 스크롤 루트로 섹션 단위 ‘스냅’ 경험을 제공합니다. 배경에는 Three.js WebGL 파티클 필드와 GLSL 리본 셰이더를 깔아 정적인 텍스트 포트폴리오에 움직임과 깊이를 더했습니다.","styles":{}}],"children":[]},{"id":"c1b70f98-4af3-4cd7-bddc-372ea2d2c0bd","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"콘텐츠(프로필 문구, 경력 타임라인, 프로젝트 카드)는 `data/` 폴더의 TypeScript 상수로 관리해 타입 안전하게 수정할 수 있습니다. GSAP ScrollTrigger로 스크롤 연동 페이드·슬라이드 애니메이션을 넣었고, Projects 섹션은 sticky 컨테이너 + translate3d 가로 스크롤 패턴으로 여러 프로젝트를 옆으로 넘기듯 보여 줍니다.","styles":{}}],"children":[]},{"id":"62dea51b-629c-426b-bd48-38745b91f4a7","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"GitHub: ","styles":{"bold":true}},{"type":"text","text":"kimkijun0226/portfolio","styles":{}}],"children":[]},{"id":"13a805a3-a518-45af-83c0-a92aa244b3ea","type":"image","props":{"backgroundColor":"default","textAlignment":"left","name":"","url":"https://picsum.photos/seed/portfolio-overview/1200/675","caption":"[임시 이미지] 포트폴리오 풀페이지 레이아웃","showPreview":true,"previewWidth":720},"children":[]},{"id":"1a685eb5-e4ba-4dc5-a80d-1bd26c089275","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[],"children":[]},{"id":"76a11f98-e7be-48d8-9657-7324585a0bcb","type":"heading","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left","level":3,"isToggleable":false},"content":[{"type":"text","text":"기술 스택 상세","styles":{}}],"children":[]},{"id":"cb624f48-c580-4ee7-8ca9-56863d4c3e01","type":"divider","props":{},"children":[]},{"id":"0d85aec4-85ed-4897-b746-d05a83ad48b0","type":"bulletListItem","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"프레임워크: Next.js 16 App Router, React 19, TypeScript","styles":{}}],"children":[]},{"id":"965369a1-9cbf-41f3-9a48-ff687ce3cfa5","type":"bulletListItem","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"스타일: Tailwind CSS v4, CSS Modules — 섹션별 레이아웃·타이포","styles":{}}],"children":[]},{"id":"cdda330f-4049-4bfb-bbfe-b1bc5e928603","type":"bulletListItem","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"애니메이션: GSAP 3 + ScrollTrigger — 스크롤 진행도에 따른 opacity·y·pin","styles":{}}],"children":[]},{"id":"9f8d059d-0d1f-43cb-be26-072512221c60","type":"bulletListItem","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"3D: Three.js — 파티클 필드, 커스텀 GLSL 리본, 다크/라이트 테마에 따른 uniform 색상","styles":{}}],"children":[]},{"id":"be180fe0-aec8-4ed5-9459-ab4253c94fdd","type":"bulletListItem","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"기타: react-icons, sonner(토스트), prefers-color-scheme 연동","styles":{}}],"children":[]},{"id":"379e1111-b8f0-4bee-80e3-030e6919771a","type":"image","props":{"backgroundColor":"default","textAlignment":"left","name":"","url":"https://picsum.photos/seed/portfolio-stack/1200/675","caption":"[임시 이미지] GSAP·Three.js 레이어","showPreview":true,"previewWidth":720},"children":[]},{"id":"de5b1b9e-e582-492b-877a-4a0de179c09e","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[],"children":[]},{"id":"b62a5e49-43e6-4d91-9a91-f0b5bf22a986","type":"heading","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left","level":3,"isToggleable":false},"content":[{"type":"text","text":"주요 구현 하이라이트","styles":{}}],"children":[]},{"id":"71fba817-307f-4f4e-b2f6-1b2750bfd199","type":"divider","props":{},"children":[]},{"id":"f2823274-16b1-4405-8d59-44c0584f92e6","type":"bulletListItem","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"ScrollRoot — overflow 스크롤 컨테이너를 직접 제어해 scroll-snap과 GSAP pin 충돌 완화","styles":{}}],"children":[]},{"id":"d2a226dc-5134-4525-9293-42f36682d5fe","type":"bulletListItem","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"ProjectsHorizontalScroll — sticky + transform 가로 이동, 휠·터치 이벤트 연동","styles":{}}],"children":[]},{"id":"92760c3e-1945-4bdd-9427-30a28b4ac5d5","type":"bulletListItem","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"useExperienceTimelineDot — Experience 섹션 스크롤에 맞춰 타임라인 dot 위치 추적","styles":{}}],"children":[]},{"id":"4d03e223-1015-436c-abad-248b37ca1896","type":"bulletListItem","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"ThreeBackground — requestAnimationFrame 루프, resize observer, 테마 변경 시 material 업데이트","styles":{}}],"children":[]},{"id":"cc35c5fa-6564-498a-9c0e-d2201139f400","type":"bulletListItem","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"data/profile.ts, experience.ts, projects.ts — 단일 소스로 카피·링크·기술 태그 관리","styles":{}}],"children":[]},{"id":"06358ab6-1461-4fa9-b28b-400503e37b0a","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[],"children":[]},{"id":"bf9387b8-4673-4b71-998e-fa660bdafccf","type":"heading","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left","level":3,"isToggleable":false},"content":[{"type":"text","text":"회고","styles":{}}],"children":[]},{"id":"4a8cff47-0476-4df9-813e-08f0a1026385","type":"divider","props":{},"children":[]},{"id":"3f738f11-e4e5-43af-b766-7f3fc73195f9","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"포트폴리오 사이트 자체를 ‘인터랙션 데모’로 만들고 싶었습니다. 스크롤 시스템 하나만 해도 scroll-snap, GSAP pin, 가로 스크롤, WebGL 배경이 서로 간섭할 수 있는데, 섹션별로 책임을 나누고 커스텀 훅으로 스크롤 진행도를 공유하면서 조화롭게 엮는 데 많은 시간을 썼습니다. 결과물은 GitHub Pages 또는 Vercel에 배포해 링크 하나로 기술 역량과 미적 감각을 동시에 보여 주는 용도로 씁니다.","styles":{}}],"children":[]},{"id":"af3a2f53-24f6-44fd-8799-4fb6fd967ca4","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[],"children":[]},{"id":"afa9e720-8a41-45e2-99fb-c0c7a5e45bd9","type":"heading","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left","level":3,"isToggleable":false},"content":[{"type":"text","text":"페이지·화면별 상세","styles":{}}],"children":[]},{"id":"aab7f9c5-5235-4dd4-93d5-652b610df56d","type":"divider","props":{},"children":[]},{"id":"374bf339-9234-4d98-a12d-55e65c521e93","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"아래는 실제 서비스를 구성하는 주요 화면 단위 설명입니다. 각 섹션마다 임시 스크린샷 이미지를 넣어 두었으며, 추후 실제 캡처로 교체할 예정입니다.","styles":{}}],"children":[]},{"id":"66d010fa-0ea1-4b78-90d7-6d2d5e0e670a","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[],"children":[]},{"id":"fd108170-626f-41a3-a2b8-4afcf4d1a222","type":"heading","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left","level":4,"isToggleable":false},"content":[{"type":"text","text":"About 섹션","styles":{}}],"children":[]},{"id":"9f6ca05f-9a04-4aad-ab95-680f068c9a2a","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"첫 화면에 이름, 직함, 한 줄 소개, SNS·이메일 링크, CTA(이력서 PDF·GitHub)를 배치합니다. Three.js 배경이 가장 두드러지게 보이는 구간이라 텍스트 대비·가독성을 신경 썼습니다.","styles":{}}],"children":[]},{"id":"e81a7953-80ff-4e6f-841d-410fb8a60a57","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"스크롤 시 GSAP으로 서브카피가 순차적으로 fade-in 되도록 했습니다.","styles":{}}],"children":[]},{"id":"6d3e0972-2bbe-4aa2-94ac-3f59836f6136","type":"image","props":{"backgroundColor":"default","textAlignment":"left","name":"","url":"https://picsum.photos/seed/portfolio-about/1200/675","caption":"[임시] About 섹션","showPreview":true,"previewWidth":720},"children":[]},{"id":"8abe2a6d-95db-4e6d-8696-0c85fe0e6923","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[],"children":[]},{"id":"d152f5e0-dc65-4736-b526-a69e99ade4c6","type":"heading","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left","level":4,"isToggleable":false},"content":[{"type":"text","text":"Experience 섹션","styles":{}}],"children":[]},{"id":"fc6b96fb-3e23-4f7a-ac9f-10ea9fa6f5a6","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"경력·교육 타임라인을 세로 라인 + dot으로 표현합니다. useExperienceTimelineDot 훅이 현재 뷰포트에 맞는 항목의 dot을 활성화합니다.","styles":{}}],"children":[]},{"id":"996541d5-2c6a-47b9-9bfc-9fe409e01c8a","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"각 항목에는 기간, 회사/기관명, 역할, 사용 기술 태그가 data/experience.ts에서 주입됩니다.","styles":{}}],"children":[]},{"id":"4ec54b5b-f3fc-4cec-9bdd-f6ccdc250941","type":"image","props":{"backgroundColor":"default","textAlignment":"left","name":"","url":"https://picsum.photos/seed/portfolio-experience/1200/675","caption":"[임시] Experience 타임라인","showPreview":true,"previewWidth":720},"children":[]},{"id":"1cc2cace-b671-41e9-9d97-2f8e58f29727","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[],"children":[]},{"id":"0e24ea02-19c8-4e4f-9107-e374d048975c","type":"heading","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left","level":4,"isToggleable":false},"content":[{"type":"text","text":"Projects 섹션","styles":{}}],"children":[]},{"id":"ae6a6ea1-75cc-49a2-9a3e-fdc43abb7ec1","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"프로젝트 카드를 가로로 나열하고, 세로 스크롤 진행도에 따라 카드 띠가 옆으로 이동합니다. 카드 클릭 시 GitHub·라이브 데모 링크로 이동합니다.","styles":{}}],"children":[]},{"id":"bcdc64b8-f00e-4ad8-aedb-12bb30f05d6d","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"My Page, 커서 커머스, 커뮤니티앱 등 다른 저장소와 상호 링크해 생태계처럼 보이게 구성했습니다.","styles":{}}],"children":[]},{"id":"28b8637f-fea1-4740-994c-3fe0a1bc08d9","type":"image","props":{"backgroundColor":"default","textAlignment":"left","name":"","url":"https://picsum.photos/seed/portfolio-projects/1200/675","caption":"[임시] Projects 가로 스크롤","showPreview":true,"previewWidth":720},"children":[]},{"id":"ca5950dd-76fb-48fd-ba8d-c396579136ec","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[],"children":[]},{"id":"2f8aa51a-ba1e-4120-ac64-f682e683ba7f","type":"heading","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left","level":4,"isToggleable":false},"content":[{"type":"text","text":"ThreeBackground·테마","styles":{}}],"children":[]},{"id":"3211c327-bf9a-4214-bec1-9a8d395a283b","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"전역 레이아웃에 고정된 canvas에서 파티클과 리본 메쉬를 렌더합니다. 라이트/다크 전환 시 particle color·ribbon gradient uniform을 업데이트합니다.","styles":{}}],"children":[]},{"id":"48d57bd8-9be4-4343-aa95-572531949223","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[{"type":"text","text":"모바일에서는 particle 수를 줄이거나 애니메이션을 완화해 성능을 확보합니다.","styles":{}}],"children":[]},{"id":"5f98565e-fcc9-4e1c-a590-0fe3e8a1448b","type":"image","props":{"backgroundColor":"default","textAlignment":"left","name":"","url":"https://picsum.photos/seed/portfolio-three/1200/675","caption":"[임시] WebGL 배경","showPreview":true,"previewWidth":720},"children":[]},{"id":"5b2403dd-4766-4a6e-a71f-f8083b46f4d8","type":"paragraph","props":{"backgroundColor":"default","textColor":"default","textAlignment":"left"},"content":[],"children":[]}]$topic127$,
